async function buildProfileCard(args, state) {
  const name = String(args.name ?? state.user_name ?? 'Гость');
  const role = String(args.role ?? 'user');
  const card = `${name} · ${role}`;
  state.react_profile_card = card;
  return {language: 'javascript', card};
}

async function summarizePriority(args: { topic?: string; priority?: number }, state: Record<string, unknown>) {
  const topic = String(args.topic ?? state.content ?? 'request');
  const priority = Number(args.priority ?? 1);
  const label = priority >= 8 ? 'high' : priority >= 4 ? 'normal' : 'low';
  state.react_priority = label;
  return {language: 'typescript', topic, priority, label};
}

