func ScoreOrder(args map[string]any, state map[string]any) (any, error) {
    amount := 0.0
    if raw, ok := args["amount"].(float64); ok {
        amount = raw
    }
    tier := "standard"
    if amount >= 10000 {
        tier = "enterprise"
    } else if amount >= 1000 {
        tier = "priority"
    }
    state["react_order_tier"] = tier
    return map[string]any{"language": "go", "amount": amount, "tier": tier}, nil
}

using System.Collections.Generic;
using System.Threading.Tasks;

Task<object?> BuildStatusCard(Dictionary<string, object?> args, Dictionary<string, object?> state)
{
    var status = args.TryGetValue("status", out var raw) && raw is not null ? raw.ToString() : "new";
    state["react_status"] = status;
    return Task.FromResult<object?>(new Dictionary<string, object?> { ["language"] = "csharp", ["status"] = status });
}
